import { tags } from 'decantr/tags';
import { createSignal, createEffect } from 'decantr/state';
import { css } from 'decantr/css';
import { Avatar, icon } from 'decantr/components';

code.example:
function MentionPopup({ collaborators, recentMentions = [], query, position, onSelect, onClose }) {
  const { div, span, button, input } = tags;
  const [selectedIndex, setSelectedIndex] = createSignal(0);

  const filterUsers = (users, q) => {
    if (!q) return users;
    const lower = q.toLowerCase();
    return users.filter(u => 
      u.name.toLowerCase().includes(lower) ||
      u.email.toLowerCase().includes(lower)
    );
  };

  const filteredUsers = filterUsers(collaborators, query);
  const showRecent = !query && recentMentions.length > 0;

  const handleKeyDown = (e) => {
    const max = filteredUsers.length - 1;
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(Math.min(selectedIndex() + 1, max));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(Math.max(selectedIndex() - 1, 0));
    } else if (e.key === 'Enter') {
      e.preventDefault();
      filteredUsers[selectedIndex()] && onSelect(filteredUsers[selectedIndex()]);
    } else if (e.key === 'Escape') {
      onClose();
    }
  };

  createEffect(() => {
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  });

  const statusColor = (status) => status === 'active' ? 'var(--success)' : status === 'idle' ? 'var(--warning)' : 'var(--text-muted)';

  const renderUser = (user, index) => button({
    class: css(`_flex _aic _gap3 _p2 _wfull _textleft _r1 ${index === selectedIndex() ? '_bg[var(--primary)/10]' : '_hover:bg[var(--surface-raised)]'}`),
    onclick: () => onSelect(user),
    onmouseenter: () => setSelectedIndex(index)
  },
    div({ class: css('_relative') },
      Avatar({ src: user.avatar, fallback: user.initials, size: 'sm' }),
      div({
        class: css('_absolute _bottom0 _right0 _w2.5 _h2.5 _rfull _ring2 _ring[var(--surface)]'),
        style: `background: ${statusColor(user.status)}`
      })
    ),
    div({ class: css('_flex _col _flex1 _min-w0') },
      span({ class: css('_textsm _fontmedium _truncate') }, user.name),
      span({ class: css('_textxs _fgmuted _truncate') }, user.email)
    ),
    user.status === 'active' ? span({ class: css('_textxs _fg[var(--success)]') }, 'Online') : null
  );

  return div({
    class: css('_absolute _bg[var(--surface)] _shadow _r2 _border _w[280px] _max-h[300px] _overflow[auto] _z[100]'),
    style: `top: ${position.y}px; left: ${position.x}px`
  },
    // Recent mentions section
    showRecent ? div({ class: css('_p2 _borderB') },
      span({ class: css('_textxs _fgmuted _fontmedium _uppercase _tracking[0.05em]') }, 'Recent'),
      div({ class: css('_flex _col _mt1') },
        ...recentMentions.slice(0, 3).map((user, i) => renderUser(user, i))
      )
    ) : null,
    // All/filtered results
    div({ class: css('_p2') },
      query ? null : span({ class: css('_textxs _fgmuted _fontmedium _uppercase _tracking[0.05em]') }, 'All collaborators'),
      filteredUsers.length > 0 ? div({ class: css('_flex _col _mt1') },
        ...filteredUsers.map((user, i) => renderUser(user, showRecent ? i + recentMentions.slice(0, 3).length : i))
      ) : div({ class: css('_py4 _textcenter _textsm _fgmuted') }, 'No matches found')
    )
  );
}

