function CompactMentionPopup({ collaborators, query, position, onSelect }) {
  const { div, span, button } = tags;
  const [selectedIndex, setSelectedIndex] = createSignal(0);

  const filtered = collaborators.filter(u => 
    u.name.toLowerCase().includes((query || '').toLowerCase())
  ).slice(0, 8);

  return div({
    class: css('_absolute _bg[var(--surface)] _shadow _r1 _border _w[200px] _z[100] _py1'),
    style: `top: ${position.y}px; left: ${position.x}px`
  },
    ...filtered.map((user, i) =>
      button({
        class: css(`_flex _aic _gap2 _px3 _py1.5 _wfull _textleft _textsm ${i === selectedIndex() ? '_bg[var(--surface-raised)]' : ''}`),
        onclick: () => onSelect(user),
        onmouseenter: () => setSelectedIndex(i)
      },
        Avatar({ src: user.avatar, fallback: user.initials, size: 'xs' }),
        span({ class: css('_truncate') }, user.name)
      )
    )
  );
}

